package search

import (
	"strings"
	"testing"
)

func TestGenerateSnippet(t *testing.T) {
	tests := []struct {
		name    string
		content string
		maxLen  int
		want    string
	}{
		{
			name:    "short content unchanged",
			content: "Short text here.",
			maxLen:  500,
			want:    "Short text here.",
		},
		{
			name:    "long content truncated at word boundary",
			content: "This is a long sentence that exceeds the limit and should be truncated at a word boundary for readability.",
			maxLen:  50,
			want:    "This is a long sentence that exceeds the limit...",
		},
		{
			name:    "empty content",
			content: "",
			maxLen:  500,
			want:    "",
		},
		{
			name:    "whitespace trimmed",
			content: "  Content with whitespace  ",
			maxLen:  500,
			want:    "Content with whitespace",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := GenerateSnippet(tt.content, tt.maxLen)
			if got != tt.want {
				t.Errorf("GenerateSnippet = %q, want %q", got, tt.want)
			}
		})
	}
}

func TestGenerateSnippetTruncation(t *testing.T) {
	// Create 600-char content
	content := strings.Repeat("word ", 120) // 600 chars
	snippet := GenerateSnippet(content, 500)

	if len(snippet) > 510 { // Allow for "..."
		t.Errorf("snippet length %d exceeds max", len(snippet))
	}
	if !strings.HasSuffix(snippet, "...") {
		t.Error("truncated snippet should end with ...")
	}
}

func TestRoundScore(t *testing.T) {
	tests := []struct {
		input float64
		want  float64
	}{
		{0.82345678, 0.8235},
		{0.71020000, 0.7102},
		{1.0, 1.0},
		{0.0, 0.0},
	}

	for _, tt := range tests {
		got := RoundScore(tt.input)
		if got != tt.want {
			t.Errorf("RoundScore(%f) = %f, want %f", tt.input, got, tt.want)
		}
	}
}
